INSERT INTO public.grammar (level_id, pattern, reading, meaning, explanation, tags, examples, order_index) VALUES
(3, '～ために', '~tame ni', 'Demi ~, Untuk tujuan ~', 'Menyatakan tujuan tindakan (sebelum kata kerja bentuk kamus/kata benda) atau menyatakan sebab/alasan (setelah kata kerja lampau/kata sifat).', ARRAY['tujuan','sebab']::text[], '[{"sentence":"日本で働くために、日本語を勉強しています。","hiragana":"にほんではたらくために、にほんごをべんきょうしています。","meaning":"Demi bekerja di Jepang, saya belajar bahasa Jepang."},{"sentence":"台風のために、電車が止まりました。","hiragana":"たいふうのために、でんしゃがとまりました。","meaning":"Karena topan, kereta berhenti."}]'::jsonb, 1),
(3, '～ようにする', '~yō ni suru', 'Berusaha untuk ~, Mencoba agar ~', 'Menyatakan usaha terus-menerus untuk membiasakan atau menghindari suatu tindakan.', ARRAY['usaha','kebiasaan']::text[], '[{"sentence":"毎日、野菜を食べるようにしています。","hiragana":"まいにち、やさいをたべるようにしています。","meaning":"Setiap hari, saya berusaha untuk makan sayuran."},{"sentence":"遅刻しないようにしてください。","hiragana":"ちこくしないようにしてください。","meaning":"Cobalah untuk tidak terlambat."}]'::jsonb, 2),
(3, '～ことにする', '~koto ni suru', 'Memutuskan untuk ~', 'Menyatakan keputusan pribadi yang dibuat oleh pembicara sendiri.', ARRAY['keputusan','niat']::text[], '[{"sentence":"今日から毎日走ることにしました。","hiragana":"きょうからまいにちはしることにしました。","meaning":"Saya memutuskan untuk berlari setiap hari mulai hari ini."},{"sentence":"タバコをやめることにします。","hiragana":"たばこをやめることにします。","meaning":"Saya memutuskan untuk berhenti merokok."}]'::jsonb, 3),
(3, '～ことになる', '~koto ni naru', 'Diputuskan bahwa ~, Ditetapkan bahwa ~', 'Menyatakan keputusan atau kesepakatan yang ditentukan oleh pihak luar atau aturan, bukan keputusan sepihak dari pembicara.', ARRAY['keputusan','aturan']::text[], '[{"sentence":"来月、日本へ出張することになりました。","hiragana":"らいげつ、にほんへしゅっちょうすることになりました。","meaning":"Telah diputuskan bahwa saya akan dinas ke Jepang bulan depan."},{"sentence":"この部屋では靴を脱ぐことになっています。","hiragana":"このへやではくつをぬぐことになっています。","meaning":"Aturannya adalah melepas sepatu di ruangan ini."}]'::jsonb, 4),
(3, '～はずだ', '~hazu da', 'Seharusnya ~, Mestinya ~', 'Menyatakan keyakinan yang kuat berdasarkan fakta atau logika logis.', ARRAY['keyakinan','logika']::text[], '[{"sentence":"彼はもう駅に着いているはずです。","hiragana":"かれはもうえきについているはずです。","meaning":"Dia seharusnya sudah sampai di stasiun."},{"sentence":"この本は面白いはずだ。","hiragana":"このほんはおもしろいはずだ。","meaning":"Buku ini mestinya menarik."}]'::jsonb, 5),
(3, '～わけだ', '~wake da', 'Pantas saja ~, Dengan kata lain ~', 'Menyatakan kesimpulan logis dari kenyataan yang dialami atau didengar. Menunjukkan pemahaman baru.', ARRAY['kesimpulan','logika']::text[], '[{"sentence":"暑いわけだ。気温が35度もある。","hiragana":"あついわけだ。きおんが35どもある。","meaning":"Pantas saja panas. Suhunya sampai 35 derajat."},{"sentence":"彼はお姉さんの夫、つまり義理の兄なわけだ。","hiragana":"かれはおねえさんのおっと、つまりぎりのあになわけだ。","meaning":"Dia adalah suami kakak perempuan saya, dengan kata lain dia adalah kakak ipar saya."}]'::jsonb, 6),
(3, '～ものだ', '~mono da', 'Memang sudah sewajarnya ~, Dulu sering ~', 'Menyatakan kebenaran umum/hukum alam, menasihati kebiasaan sosial yang wajar, atau menyatakan nostalgia masa lalu (bentuk ~たものだ).', ARRAY['kebiasaan','norma','nostalgia']::text[], '[{"sentence":"子供はよく遊ぶものだ。","hiragana":"こどもはよくあそぶものだ。","meaning":"Anak-anak memang sudah sewajarnya banyak bermain."},{"sentence":"学生のころは、よくこの店に来たものだ。","hiragana":"がくせいのころは、よくこのみせにきたものだ。","meaning":"Zaman sekolah dulu, saya sering datang ke toko ini."}]'::jsonb, 7),
(3, '～に対して', '~ni taishite', 'Terhadap ~, Berbeda dengan ~', 'Menyatakan sikap/tindakan kepada seseorang/objek, atau membandingkan dua hal yang bertolak belakang.', ARRAY['sikap','kontras']::text[], '[{"sentence":"お客様に対して、丁寧な言葉を使いましょう。","hiragana":"おきゃくさまにたいして、ていねいなことばをつかいましょう。","meaning":"Mari gunakan bahasa yang sopan terhadap pelanggan."},{"sentence":"兄が静かなのに対して、弟はとても賑やかだ。","hiragana":"あにがしずかなのにたいして、おとうとはとてもにぎやかだ。","meaning":"Berbeda dengan kakak laki-laki yang pendiam, adik laki-lakinya sangat ramai."}]'::jsonb, 8),
(3, '～によって', '~ni yotte', 'Oleh ~, Karena ~, Melalui ~, Bergantung pada ~', 'Menunjukkan pelaku (kalimat pasif), sebab-akibat, metode/cara, atau variasi kasus.', ARRAY['metode','sebab','pelaku','variasi']::text[], '[{"sentence":"このビルは有名な建築家によって設計された。","hiragana":"このびるはゆうめいなけんちくかによってせっけいされた。","meaning":"Gedung ini dirancang oleh arsitek terkenal."},{"sentence":"人によって考え方が違います。","hiragana":"ひとによってかんがえかたちがちいます。","meaning":"Cara berpikir berbeda-beda bergantung pada orangnya."}]'::jsonb, 9),
(3, '～に関して', '~ni kanshite', 'Mengenai ~, Berkaitan dengan ~', 'Memperkenalkan topik pembicaraan atau tulisan secara formal (lebih formal dari ～について).', ARRAY['topik','formal']::text[], '[{"sentence":"この事件に関して, 警察が調べています。","hiragana":"このじけんにかんして、けいさつがしらべています。","meaning":"Mengenai kasus ini, polisi sedang menyelidiki."},{"sentence":"日本の文化に関する本を読みました。","hiragana":"にほんのぶんかにかんするほんをよみました。","meaning":"Saya membaca buku yang berkaitan dengan budaya Jepang."}]'::jsonb, 10),
(3, '～てしまう', '~te shimau', 'Sudah terlanjur ~, Berhasil menyelesaikan ~', 'Menyatakan penyesalan atas kejadian yang terlanjur terjadi, atau penyelesaian suatu aksi secara tuntas.', ARRAY['penyesalan','selesai']::text[], '[{"sentence":"大切な財布を電車の中に忘れてしまいました。","hiragana":"たいせつなさいふをでんしゃのなかにわすれてしまいました。","meaning":"Saya terlanjur meninggalkan dompet berharga saya di dalam kereta."},{"sentence":"この宿題は今日中にやってしまいます。","hiragana":"このしゅくだいはきょうじゅうにやってしまいます。","meaning":"PR ini akan saya selesaikan hari ini."}]'::jsonb, 11),
(3, '～ていく・てくる', '~te iku / ~te kuru', 'Terus ~ (menjauh) / Mulai ~ (mendekat)', 'Menunjukkan arah perkembangan waktu/kejadian: ていく menjauh dari masa kini ke masa depan; てくる mendekat dari masa lalu ke masa kini.', ARRAY['perubahan','waktu']::text[], '[{"sentence":"これからも日本語を勉強していきます。","hiragana":"これからもにほんごをべんきょうしていきます。","meaning":"Mulai sekarang pun saya akan terus belajar bahasa Jepang."},{"sentence":"だんだん寒くなってきました。","hiragana":"だんだんさむくなってきました。","meaning":"Perlahan-lahan cuaca mulai mendingin."}]'::jsonb, 12),
(3, '～ことになっている', '~koto ni natte iru', 'Sudah dijadwalkan bahwa ~, Ditetapkan bahwa ~', 'Menyatakan aturan tetap atau rencana yang sudah disepakati secara resmi dan masih berlaku.', ARRAY['aturan','jadwal']::text[], '[{"sentence":"金曜日に会議を行うことになっています。","hiragana":"きんようびにかいぎをおこなうことになっています。","meaning":"Rapat telah dijadwalkan diadakan pada hari Jumat."},{"sentence":"ここではタバコを吸ってはいけないことになっています。","hiragana":"ここではたばこをすってはいけないことになっています。","meaning":"Aturannya adalah dilarang merokok di sini."}]'::jsonb, 13),
(3, '～ばいい', '~ba ii', 'Sebaiknya ~, Tinggal ~ saja', 'Memberikan saran ringan atau rekomendasi tindakan sederhana untuk memecahkan masalah.', ARRAY['saran','solusi']::text[], '[{"sentence":"わからないときは、先生に聞けばいいです。","hiragana":"わからないときは、せんせいにきけばいいです。","meaning":"Saat tidak mengerti, sebaiknya bertanya kepada guru."},{"sentence":"このボタンを押せばいいですよ。","hiragana":"このぼたんをおせばいいですよ。","meaning":"Tinggal tekan tombol ini saja lho."}]'::jsonb, 14),
(3, '～うちに', '~uchi ni', 'Selagi ~, Sebelum ~', 'Melakukan tindakan selagi keadaan masih mendukung, sebelum keadaan tersebut berubah.', ARRAY['waktu','kondisi']::text[], '[{"sentence":"若いうちに、いろいろな国へ行きたいです。","hiragana":"わかいうちに、いろいろなくにへいきたいです。","meaning":"Selagi masih muda, saya ingin pergi ke berbagai negara."},{"sentence":"雨が降らないうちに、家に帰りましょう。","hiragana":"あめがふらないうちに、いえにかえりましょう。","meaning":"Sebelum hujan turun, mari pulang ke rumah."}]'::jsonb, 15),
(3, '～最中に', '~saichū ni', 'Di tengah-tengah ~, Pas lagi ~', 'Menyatakan tindakan tak terduga yang mengganggu ketika suatu aksi sedang dilakukan dengan fokus penuh.', ARRAY['waktu','kejadian']::text[], '[{"sentence":"会議の最中に, 地震が起きました。","hiragana":"かいぎのさいちゅうに、じしんがおきました。","meaning":"Di tengah-tengah rapat, gempa bumi terjadi."},{"sentence":"電話をしている最中に、チャイムが鳴った。","hiragana":"でんわをしているさいちゅうに、ちゃいむがなった。","meaning":"Pas lagi teleponan, bel pintu berbunyi."}]'::jsonb, 16),
(3, '～かけだ・かけの', '~kake da / ~kake no', 'Setengah selesai ~, Baru mulai ~', 'Menyatakan aksi yang sedang dilakukan namun belum selesai sempurna dan terhenti sementara.', ARRAY['kondisi','progres']::text[], '[{"sentence":"テーブルの上に飲みかけのコップがある。","hiragana":"てーぶるのうえにのみかけのこっぷがある。","meaning":"Ada cangkir berisi minuman yang setengah diminum di atas meja."},{"sentence":"この本はまだ読みかけです。","hiragana":"このほんはまだよみかけです。","meaning":"Buku ini masih setengah dibaca."}]'::jsonb, 17),
(3, '～きる', '~kiru', 'Selesai sepenuhnya, Sangat ~', 'Menyatakan tindakan yang diselesaikan secara tuntas atau kondisi ekstrem (sangat lelah/yakin).', ARRAY['tuntas','ekstrem']::text[], '[{"sentence":"長い小説を、一晩で読みきりました。","hiragana":"ながいしょうせつを、ひとばんではしりきりました。","meaning":"Saya selesai membaca novel panjang itu dalam satu malam."},{"sentence":"今日は本当に疲れきった。","hiragana":"きょうはほんとうにつかれきった。","meaning":"Hari ini saya benar-benar sangat lelah."}]'::jsonb, 18),
(3, '～がちだ', '~gachi da', 'Cenderung sering ~, Gampang ~', 'Menyatakan kecenderungan negatif yang sering terjadi (misal: gampang sakit, sering lupa).', ARRAY['negatif','kecenderungan']::text[], '[{"sentence":"最近、彼は仕事を休みがちだ。","hiragana":"さいきん、かれはしごとをやすみがちだ。","meaning":"Akhir-akhir ini dia cenderung sering tidak masuk kerja."},{"sentence":"一人暮らしは野菜が不足しがちになります。","hiragana":"ひとりぐらしはやさいがふそくしがちになります。","meaning":"Tinggal sendiri cenderung gampang kekurangan sayur."}]'::jsonb, 19),
(3, '～だらけ', '~darake', 'Penuh dengan ~ (negatif)', 'Menyatakan permukaan yang tertutup oleh hal buruk/negatif (seperti lumpur, darah, kesalahan).', ARRAY['kondisi','negatif']::text[], '[{"sentence":"彼の部屋はゴミだらけだ。","hiragana":"かれのへやはごみだらけだ。","meaning":"Kamarnya penuh dengan sampah."},{"sentence":"テストの答えは間違いだらけだった。","hiragana":"てすとのこたえはまちがいだらけだった。","meaning":"Jawaban ujiannya penuh dengan kesalahan."}]'::jsonb, 20),
(3, '～っぽい', '~ppoi', 'Kelihatan seperti ~, Cenderung mudah ~', 'Menyatakan karakteristik yang menyerupai sesuatu (sifat kekanakan, warna kehitaman) atau gampang (lupa).', ARRAY['sifat','kecenderungan']::text[], '[{"sentence":"あの人は子供っぽいです。","hiragana":"あのひとはこどもっぽいです。","meaning":"Orang itu kekanak-kanakan."},{"sentence":"年を取ると、忘れっぽくなります。","hiragana":"としをとると、わすれっぽくなります。","meaning":"Seiring bertambahnya usia, orang cenderung gampang lupa."}]'::jsonb, 21),
(3, '～がたい', '~gatai', 'Sulit untuk dilakukan ~', 'Menyatakan ketidakmampuan secara emosional atau psikologis untuk melakukan sesuatu (sulit dimaafkan, dipercaya).', ARRAY['kemampuan','psikologis']::text[], '[{"sentence":"彼の話は信じがたい。","hiragana":"かれのはなしはしんじがたい。","meaning":"Ceritanya sulit untuk dipercaya."},{"sentence":"それは許しがたい行為だ。","hiragana":"それはゆるしがたいこういだ。","meaning":"Itu adalah tindakan yang sulit dimaafkan."}]'::jsonb, 22),
(3, '～がする', '~ga suru', 'Terasa ~, Berbau ~, Terdengar ~', 'Menyatakan persepsi sensorik alami (suara, bau, rasa, firasat) yang ditangkap panca indera.', ARRAY['indera','firasat']::text[], '[{"sentence":"隣の部屋から変な音がします。","hiragana":"となりのへやからへんなおとがします。","meaning":"Terdengar suara aneh dari kamar sebelah."},{"sentence":"いい匂いがしますね。","hiragana":"いいにおいがしますね。","meaning":"Baunya wangi ya."}]'::jsonb, 23),
(3, '～らしい', '~rashii', 'Sepertinya ~, Khas/layak ~', 'Menyatakan dugaan berdasarkan informasi tidak langsung, atau menyatakan karakteristik ideal (seperti pria sejati, hari yang sangat musim semi).', ARRAY['dugaan','karakteristik']::text[], '[{"sentence":"明日は雨らしいです。","hiragana":"あしたはあめらしいです。","meaning":"Sepertinya besok hujan."},{"sentence":"今日は春らしい暖かい日ですね。","hiragana":"きょうははるらしいあたたかいひですね。","meaning":"Hari ini hari hangat yang khas musim semi ya."}]'::jsonb, 24),
(3, '～みたいだ', '~mitai da', 'Seperti ~, Tampaknya ~', 'Menyatakan kemiripan (metafora) atau dugaan kuat berdasarkan pengamatan langsung (kasual, mirip ようだ).', ARRAY['kemiripan','dugaan']::text[], '[{"sentence":"彼女はモデルみたいにスタイルが良い。","hiragana":"かのじょはモデルみたいにすたいるがよい。","meaning":"Dia memiliki postur tubuh bagus seperti model."},{"sentence":"会議はもう終わったみたいだ。","hiragana":"かいぎはもうおわったみたいだ。","meaning":"Rapatnya tampaknya sudah selesai."}]'::jsonb, 25),
(3, '～に違いない', '~ni chigai nai', 'Pasti ~, Tidak salah lagi ~', 'Menyatakan keyakinan subjektif pembicara yang sangat kuat terhadap suatu hal.', ARRAY['keyakinan','subjektif']::text[], '[{"sentence":"犯人はあの人に違いない。","hiragana":"はんにんはあのひとにちがいない。","meaning":"Pelakunya pasti orang itu."},{"sentence":"彼女は毎日勉強しているから、合格するに違いない。","hiragana":"かのじょはまいにちべんきょうしているから、ごうかくするにちがいない。","meaning":"Karena dia belajar setiap hari, dia pasti lulus."}]'::jsonb, 26),
(3, '～わけがない', '~wake ga nai', 'Tidak mungkin ~, Mustahil ~', 'Menolak keras suatu kemungkinan berdasarkan alasan logis yang kuat.', ARRAY['penolakan','logika']::text[], '[{"sentence":"そんなに練習したのに、負けるわけがない。","hiragana":"そんなにれんしゅうしたのに、まけるわけがない。","meaning":"Meskipun sudah berlatih keras seperti itu, tidak mungkin kalah."},{"sentence":"彼が嘘をつくわけがない。","hiragana":"かれがうそをつくわけがない。","meaning":"Mustahil dia berbohong."}]'::jsonb, 27),
(3, '～わけではない', '~wake dewa nai', 'Bukan berarti ~, Tidak selalu ~', 'Membantah kesimpulan umum secara halus. Menyatakan kebenaran parsial.', ARRAY['sanggahan','parsial']::text[], '[{"sentence":"日本人が全員アニメが好きというわけではない。","hiragana":"にほんじんがぜんいんアニメがすきというわけではない。","meaning":"Bukan berarti semua orang Jepang suka anime."},{"sentence":"お金がたくさんあれば幸せになれるわけではない。","hiragana":"おかねがたくさんあればしあわせになれるわけではない","meaning":"Punya banyak uang tidak selalu berarti bisa bahagia."}]'::jsonb, 28),
(3, '～わけにはいかない', '~wake niwa ikanai', 'Tidak boleh ~, Tidak bisa (moral/situasi)', 'Menyatakan ketidakbisaan melakukan sesuatu karena alasan moral, tanggung jawab, atau norma sosial.', ARRAY['kewajiban','moral']::text[], '[{"sentence":"明日は大事な試験があるから、休むわけにはいかない。","hiragana":"あしたはだいじなしけんがあるから、やすむわけにはいかない。","meaning":"Karena besok ada ujian penting, saya tidak boleh absen."},{"sentence":"車の運転があるから、お酒を飲むわけにはいかない。","hiragana":"くるまのうんてんがあるから、おさけをのむわけにはいかない。","meaning":"Karena harus menyetir mobil, saya tidak boleh minum alkohol."}]'::jsonb, 29),
(3, '～さえ', '~sae', 'Bahkan ~, Pun ~', 'Menyatakan contoh ekstrem untuk menunjukkan bahwa hal lain yang biasa tentu lebih demikian.', ARRAY['penekanan','ekstrem']::text[], '[{"sentence":"ひらがなさえ書けない子供が、この本を読めるわけがない。","hiragana":"ひらがなさえかけないこどもが、このほんをよめるわけがない。","meaning":"Anak yang bahkan tidak bisa menulis hiragana, tidak mungkin bisa membaca buku ini."},{"sentence":"忙しくて、食事をする時間さえありません。","hiragana":"いそがしくて、しょくじをするじかんさえありません。","meaning":"Saking sibuknya, bahkan tidak ada waktu makan."}]'::jsonb, 30),
(3, '～さえ～ば', '~sae ~ba', 'Asal ~ saja, Hanya dengan ~', 'Menyatakan satu-satunya syarat mutlak yang diperlukan agar suatu hal dapat terwujud.', ARRAY['syarat','mutlak']::text[], '[{"sentence":"薬を飲みさえすれば、病気は治ります。","hiragana":"くすりをおみさえすれば、びょうきはなおります。","meaning":"Asal minum obat saja, penyakit akan sembuh."},{"sentence":"あなたさえいれば、何もいりません。","hiragana":"あなたさえいれば、なにもいりません。","meaning":"Asal ada kamu saja, saya tidak butuh apa-apa."}]'::jsonb, 31),
(3, '～こそ', '~koso', 'Justru ~, Justru karena ~', 'Menekankan kata sebelumnya sebagai hal yang paling tepat atau utama dibanding yang lain.', ARRAY['penekanan']::text[], '[{"sentence":"今年こそ、JLPT N3に合格したいです。","hiragana":"ことこそ、JLPT N3にごうかくしたいです。","meaning":"Justru tahun ini, saya ingin lulus JLPT N3."},{"sentence":"こちらこそ、よろしくお願いします。","hiragana":"こちらこそ、よろしくおねがいします。","meaning":"Justru saya yang harus meminta bantuan Anda (sama-sama)."}]'::jsonb, 32),
(3, '～ばかりか', '~bakari ka', 'Bukan hanya ~, Malahan ~ juga', 'Menyatakan bahwa tidak hanya hal tersebut yang terjadi, melainkan ada hal lain yang tingkatannya lebih ekstrem.', ARRAY['tambahan','ekstrem']::text[], '[{"sentence":"彼は漢字が読めるばかりか、書くこともできる。","hiragana":"かれはかんじがよめるばかりか、かくこともできる。","meaning":"Dia bukan hanya bisa membaca kanji, malahan bisa menulisnya juga."},{"sentence":"雨が降ってきたばかりか、雷も鳴り始めた。","hiragana":"あめがふってきたばかりか、かみなりもなりはじめた。","meaning":"Bukan hanya hujan mulai turun, malahan petir juga mulai berbunyi."}]'::jsonb, 33),
(3, '～おかげで', '~okage de', 'Berkat ~, Untung saja karena ~', 'Menyatakan rasa syukur atas sebab yang membawa hasil positif.', ARRAY['sebab','positif','syukur']::text[], '[{"sentence":"先生のおかげで, N4に合格できました。","hiragana":"せんせいのおかげで、N4にごうかくできました。","meaning":"Berkat guru, saya bisa lulus N4."},{"sentence":"天気が良いおかげで、洗濯物がすぐ乾いた。","hiragana":"てんきがよいおかげで、せんたくものがすぐかわいた。","meaning":"Untung saja cuaca bagus, jemuran langsung kering."}]'::jsonb, 34),
(3, '～せいで', '~sei de', 'Gara-gara ~, Akibat dari ~', 'Menyatakan keluhan atas sebab yang mendatangkan hasil negatif.', ARRAY['sebab','negatif','keluhan']::text[], '[{"sentence":"雨のせいで, 遠足が中止になりました。","hiragana":"あめのせいで、えんそくがちゅうしになりました。","meaning":"Gara-gara hujan, karyawisata dibatalkan."},{"sentence":"寝不足のせいで, 今日は頭が痛い。","hiragana":"ねぶそくのせいで、きょうはあたまがいたい。","meaning":"Gara-gara kurang tidur, hari ini kepala saya sakit."}]'::jsonb, 35),
(3, '～うえに', '~ue ni', 'Selain ~, Terlebih lagi ~', 'Menambahkan poin positif pada hal positif lain, atau poin negatif pada hal negatif lain.', ARRAY['tambahan']::text[], '[{"sentence":"この店の料理は美味しい上に、安い。","hiragana":"このみせのりょうりはおいしいうえに、やすい。","meaning":"Masakan toko ini selain enak, terlebih lagi murah."},{"sentence":"道に迷った上に、雨が降り出した。","hiragana":"みちにまよったうえに、あめがふりだした。","meaning":"Selain tersesat jalan, terlebih lagi hujan mulai turun."}]'::jsonb, 36),
(3, '～に比べて', '~ni kurabete', 'Dibandingkan dengan ~', 'Membuat perbandingan formal antara dua hal.', ARRAY['perbandingan']::text[], '[{"sentence":"去年 に比べて、今年はとても暖かい。","hiragana":"きょねんにくらべて、ことしはとてもあたたかい。","meaning":"Dibandingkan tahun lalu, tahun ini sangat hangat."},{"sentence":"電車はバスに比べて、遅れることが少ない。","hiragana":"でんしゃはばすにくらべて、おくれることがすくない。","meaning":"Kereta dibandingkan bus, lebih jarang terlambat."}]'::jsonb, 37),
(3, '～として', '~toshite', 'Sebagai ~', 'Menunjukkan status, jabatan, fungsi, atau kapasitas dari seseorang/sesuatu.', ARRAY['fungsi','status']::text[], '[{"sentence":"日本へSSWとして行く予定です。","hiragana":"にほんへSSWとしていくよていです。","meaning":"Saya berencana pergi ke Jepang sebagai pekerja SSW."},{"sentence":"趣味として、日本語を勉強しています。","hiragana":"しゅみとして、にほんごをべんきょうしています。","meaning":"Saya belajar bahasa Jepang sebagai hobi."}]'::jsonb, 38),
(3, '～に基づいて', '~ni motozuite', 'Berdasarkan ~, Berlandaskan ~', 'Menyatakan bahwa suatu tindakan/karya dibuat dengan menggunakan fakta/data/rencana sebagai dasar.', ARRAY['dasar','formal']::text[], '[{"sentence":"この小説は、事実に基づいて書かれています。","hiragana":"このしょうせつは、じじつにもとづいてかかれています。","meaning":"Novel ini ditulis berdasarkan fakta nyata."},{"sentence":"計画に基づいて進めてください。","hiragana":"けいかくにもとづいてすすめてください。","meaning":"Tolong jalankan berdasarkan rencana."}]'::jsonb, 39),
(3, '～において', '~ni oite', 'Di ~, Pada ~ (formal)', 'Menyatakan tempat atau bidang terjadinya suatu peristiwa secara formal (pengganti partikel で/に).', ARRAY['tempat','formal']::text[], '[{"sentence":"入学式は体育館において行われます。","hiragana":"にゅうがくしきはたいいくかんにおいておこなわれます。","meaning":"Upacara penerimaan siswa baru diadakan di aula olahraga."},{"sentence":"現代社会において, ITは欠かせない。","hiragana":"げんだいしゃかいにおいて、ITはかかせない。","meaning":"Pada masyarakat modern, IT tidak boleh terlewatkan."}]'::jsonb, 40),
(3, '～べきだ', '~beki da', 'Seharusnya ~, Wajib ~', 'Menyatakan saran moral atau kewajiban kuat yang didasarkan pada akal sehat sosial.', ARRAY['kewajiban','saran']::text[], '[{"sentence":"約束は守るべきだ。","hiragana":"やくそくはまもるべきだ。","meaning":"Janji itu seharusnya ditepati."},{"sentence":"お年寄りには席を譲るべきです。","hiragana":"おとしよりにはせきをゆずるべきです。","meaning":"Kepada lansia seharusnya memberikan kursi."}]'::jsonb, 41),
(3, '～ざるを得ない', '~zaru wo enai', 'Terpaksa harus ~, Mau tidak mau harus ~', 'Menyatakan tindakan yang terpaksa dilakukan karena tidak ada pilihan lain dari situasi tersebut.', ARRAY['terpaksa','kewajiban']::text[], '[{"sentence":"台風で電車がないため、歩いて帰らざるを得ない。","hiragana":"たいふうででんしゃがないため、あるいてかえらざるをえない。","meaning":"Karena tidak ada kereta akibat topan, saya terpaksa pulang dengan berjalan kaki."},{"sentence":"彼の意見を認めざるを得ない。","hiragana":"かれのいけんをみとめざるをえない。","meaning":"Mau tidak mau harus mengakui pendapatnya."}]'::jsonb, 42),
(3, '～ようがない', '~yō ga nai', 'Tidak ada cara untuk ~', 'Menyatakan kemustahilan total karena tidak ada metode/sarana yang tersisa untuk melakukannya.', ARRAY['kemampuan','mustahil']::text[], '[{"sentence":"連絡先がわからないので, 連絡しようがない。","hiragana":"れんらくさきがわからないので、れんらくしようがない。","meaning":"Karena tidak tahu kontaknya, tidak ada cara untuk menghubungi."},{"sentence":"この携帯は壊れているから、直しようがない。","hiragana":"このけいたいはこわれているから、なおしようがない。","meaning":"Karena ponsel ini rusak parah, tidak ada cara untuk memperbaikinya."}]'::jsonb, 43),
(3, '～かねない', '~kanenai', 'Bisa-bisa ~, Ada kemungkinan buruk ~', 'Menyatakan kekhawatiran akan hasil buruk atau bahaya yang berpeluang besar terjadi.', ARRAY['bahaya','dugaan']::text[], '[{"sentence":"スピードを出すと、事故を起こしかねない。","hiragana":"すぴーどをだすと、じこをおこしかねない。","meaning":"Jika mengebut, bisa-bisa memicu kecelakaan."},{"sentence":"秘密を話すと, 友達関係が壊れかねません。","hiragana":"ひみつをはなすと、ともだちかんけいがこわれかねません。","meaning":"Jika membocorkan rahasia, hubungan pertemanan bisa-bisa rusak."}]'::jsonb, 44),
(3, '～かねる', '~kaneru', 'Sulit untuk ~, Tidak bisa (halus)', 'Menolak secara halus atau menyatakan ketidakbisaan karena pertimbangan psikologis/formal.', ARRAY['penolakan','sopan']::text[], '[{"sentence":"申し訳ありませんが、その質問にはお答えしかねます。","hiragana":"もうしわけありませんが、そのしつもんにはおこたえしかねます。","meaning":"Mohon maaf sebesar-sebesar, saya sulit untuk menjawab pertanyaan tersebut (tidak bisa)."},{"sentence":"彼の提案は賛成しかねる。","hiragana":"かれのていあんはさんせいしかねる。","meaning":"Usulannya sulit untuk saya setujui."}]'::jsonb, 45),
(3, '～おそれがある', '~osore ga aru', 'Khawatir akan ~, Terancam ~ (buruk)', 'Menyatakan kekhawatiran formal bahwa peristiwa buruk/bencana alam akan terjadi.', ARRAY['bahaya','formal']::text[], '[{"sentence":"今夜は台風が上陸するおそれがあります。","hiragana":"こんやはたいふうがじょうりくするおそれがあります。","meaning":"Malam ini dikhawatirkan topan akan mendarat."},{"sentence":"この病気は感染するおそれがあります。","hiragana":"このびょうきはかんせんするおそれがあります。","meaning":"Penyakit ini dikhawatirkan menular."}]'::jsonb, 46),
(3, '～わりに（は）', '~wari ni (wa)', 'Padahal ~, Dibandingkan dengan keadaannya ~', 'Menyatakan hasil yang tidak sebanding atau tidak terduga dari fakta standar pendukung sebelumnya.', ARRAY['kontras','tidak terduga']::text[], '[{"sentence":"彼はたくさん食べるわりに、太らない。","hiragana":"かれはたくさんたべるわりに、ふとらない。","meaning":"Dia padahal makan banyak, tapi tidak gemuk."},{"sentence":"この料理は簡単なわりに、美味しい。","hiragana":"このりょうりはかんたんなわりに、おいしい。","meaning":"Masakan ini padahal mudah dibuat, tapi enak."}]'::jsonb, 47),
(3, '～くせに', '~kuse ni', 'Padahal ~ (kesal/mencela)', 'Menyatakan celaan/kritik tajam karena kelakuan bertolak belakang dengan identitas/kemampuan subjek.', ARRAY['kontras','celaan']::text[], '[{"sentence":"彼は男のくせに、いつも泣いている。","hiragana":"かれはおとこのくせに、いつもないている。","meaning":"Dia padahal laki-laki, tapi menangis terus."},{"sentence":"知らないくせに、知っているふりをしている。","hiragana":"しらないくせに、しっているふりをしている。","meaning":"Padahal tidak tahu, tapi sok tahu."}]'::jsonb, 48),
(3, '～にもかかわらず', '~nimo kakawarazu', 'Meskipun ~, Walaupun ~ (formal)', 'Menyatakan kontras yang kuat antara kenyataan hasil dengan keadaan pendukung secara formal.', ARRAY['kontras','formal']::text[], '[{"sentence":"雨が降っているにもかかわらず、多くの人が集まりました。","hiragana":"あめがふっているにもかかわらず、おおくのひとがあつまりました。","meaning":"Meskipun hujan turun, banyak orang tetap berkumpul."},{"sentence":"努力したにもかかわらず、不合格だった。","hiragana":"どりょくしたにもかかわらず、ふごうかくだった。","meaning":"Meskipun sudah berusaha keras, hasilnya tidak lulus."}]'::jsonb, 49),
(3, 'たとえ～ても', 'tatoe ~te mo', 'Walaupun ~ sekalipun', 'Menyatakan pengandaian ekstrem yang tidak akan mempengaruhi keputusan atau hasil akhir.', ARRAY['pengandaian','ekstrem']::text[], '[{"sentence":"たとえ雨が降っても, 試合は行います。","hiragana":"たとえあめがふっても、しあいはあこないます。","meaning":"Walaupun hujan turun sekalipun, pertandingan tetap diadakan."},{"sentence":"たとえ反対されても、私は日本へ行きます。","hiragana":"たとえはんたいされても、わたしはにほんへいきます。","meaning":"Walaupun ditentang sekalipun, saya akan tetap pergi ke Jepang."}]'::jsonb, 50);
